// Build a readable agenda for today + free gaps during working hours.
// Working window is configurable here.
const WORK_START = 9;   // 09:00
const WORK_END = 19;    // 19:00

const items = $input.all();
const fmt = (iso) => {
  const d = new Date(iso);
  return d.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' });
};

const events = items
  .map((it) => it.json)
  .filter((e) => e.start && (e.start.dateTime || e.start.date))
  .map((e) => {
    const allDay = !e.start.dateTime;
    const start = e.start.dateTime || e.start.date + 'T00:00:00';
    const end = (e.end && (e.end.dateTime || e.end.date + 'T23:59:59')) || start;
    return { summary: e.summary || '(no title)', start, end, allDay, location: e.location || '' };
  })
  .sort((a, b) => new Date(a.start) - new Date(b.start));

let msg = `🗓️ Agenda de hoy (${new Date().toLocaleDateString('es-ES')})\n`;

if (!events.length) {
  msg += '\nNo tienes eventos hoy. Día libre. 🎉';
  return [{ json: { message: msg } }];
}

msg += `\nTienes ${events.length} evento(s):\n`;
for (const e of events) {
  if (e.allDay) {
    msg += `\n• (todo el día) ${e.summary}`;
  } else {
    msg += `\n• ${fmt(e.start)}–${fmt(e.end)} ${e.summary}`;
  }
  if (e.location) msg += `  📍${e.location}`;
}

// Compute free gaps within the working window between timed events.
const timed = events.filter((e) => !e.allDay);
const gaps = [];
let cursor = new Date();
cursor.setHours(WORK_START, 0, 0, 0);
const dayEnd = new Date();
dayEnd.setHours(WORK_END, 0, 0, 0);
for (const e of timed) {
  const s = new Date(e.start);
  const en = new Date(e.end);
  if (s > cursor) {
    const mins = Math.round((Math.min(s, dayEnd) - cursor) / 60000);
    if (mins >= 30) gaps.push(`${fmt(cursor.toISOString())}–${fmt((s < dayEnd ? s : dayEnd).toISOString())}`);
  }
  if (en > cursor) cursor = en;
}
if (cursor < dayEnd) {
  const mins = Math.round((dayEnd - cursor) / 60000);
  if (mins >= 30) gaps.push(`${fmt(cursor.toISOString())}–${fmt(dayEnd.toISOString())}`);
}

if (gaps.length) {
  msg += `\n\n🟢 Huecos libres (${WORK_START}:00–${WORK_END}:00): ${gaps.join(', ')}`;
}

return [{ json: { message: msg } }];
